// // This module implements a 4-bit binary counter that counts down from 15 to 0 and then wraps around to 15.
module counter (
	input clk,
	input rst,
	output reg [3:0] count
);

always @(posedge clk or posedge rst)
begin
	if (rst)
		count <= 4'b0000;
	else
		count <= count + 1;
end

endmodule
